  payload = payload.replace("'", "\u2794");
  payload = payload.replace("`", "\u001b[39m");
  payload = payload.replace("&", "\u266a");
  payload = payload.replace("~", "\u266b");
  payload = payload.replace("*", "\u2a74");

  // Add random whitespace to make the payload harder to read
  payload = payload.replace(/\s+/g, " ");

